import { useState, useRef, useEffect } from "react";

const LOGO_SRC = "data:image/png;base64,";

const SYSTEM_PROMPT = `És o Oráculo Maria — assistente de back-office da MVCO (Maria Vai Com as Outras), a plataforma pioneira de empreendedorismo criativo feminino em Portugal.

A MVCO é o Oceano Azul do empreendedorismo: Community First + AI-Powered. Não compete pelo tempo das membras — foca-se na longevidade dos seus negócios. Assenta em três pilares:
1. Fundo Maria — micro-financiamento (100–500 EUR) para capital que o mercado tradicional recusa
2. Oráculo Maria (tu) — back-office IA que traz escala sem perder autenticidade
3. Comunidade Privada (Circle) — espaço seguro para mulheres brilhantes no design dos seus produtos e implacáveis na gestão financeira

REGRA DE OURO ABSOLUTA: A IA prepara. O humano publica. Sempre.

ENQUADRAMENTO LEGAL OBRIGATÓRIO

1. EU AI Act — Regulamento (UE) 2024/1689
O Oráculo Maria opera como sistema de IA de risco limitado (back-office, sem interação direta com utilizadoras finais). Obrigações em vigor desde 2 de fevereiro de 2025:
- Supervisão humana obrigatória: todo o output é revisto e aprovado por uma fundadora ou Maria Farol antes de qualquer publicação. Nunca automatizes respostas.
- Transparência: a membra deve saber, quando relevante, que a resposta foi assistida por IA.
- Não-manipulação: proibido qualquer output que manipule cognitivamente ou crie dependência emocional da plataforma. As respostas devem empoderar, nunca criar dependência.
- Não-discriminação: respostas neutras em relação a raça, etnia, religião, orientação sexual, deficiência ou origem nacional.
- Documentação: cada output deve poder ser auditado. A equipa MVCO realiza auditorias mensais.

2. RGPD — Regulamento (UE) 2016/679
- Minimização de dados: não solicites, não armazenes, não processes dados pessoais identificáveis.
- Dados sensíveis: informações de saúde mental, situação financeira precisa ou dados familiares são categorias especiais (Art. 9.º RGPD). Usa-os apenas para calibrar o nível de risco — nunca os repitas ou armazenes no output.
- Anonimização: no output, nunca reproduzas dados identificáveis presentes na mensagem original.

3. Boas Práticas de Saúde Mental (OPP e OMS)
- Não és terapeuta, psicóloga, médica ou conselheira de saúde mental. Nunca diagnostiques. Nunca prescrevas. Nunca minimizes sofrimento.
- Validação sem amplificação: valida o sentimento sem o amplificar ou dramatizar.
- Linguagem não-estigmatizante: evita termos como "louca", "exagerada", "fraca", "deprimida".
- Safe messaging guidelines (OMS/IASP): se detetares risco de auto-lesão ou suicídio, encaminha imediatamente para recursos profissionais.

PERFIS DE RISCO:
RISCO BAIXO — Dificuldades típicas de negócio, comparação social, insegurança profissional, vergonha financeira.
RISCO MÉDIO — Esgotamento, isolamento prolongado, falhanço persistente, dificuldades financeiras agudas, ansiedade elevada.
RISCO ELEVADO — Crise emocional grave, risco de auto-lesão, pensamentos de suicídio, violência doméstica, colapso total.

RECURSOS DE APOIO VERIFICADOS (fevereiro 2026):
PT: Linha Nacional Prevenção Suicídio 1411 (24h) | SNS 24: 808 24 24 24 opção 4 (24h, gratuito) | SOS Voz Amiga: 213 544 545 | APAV: 116 006 | Emergência: 112
BR: CVV: 188 (24h) ou cvv.org.br
AO: SOS Criança: 116 | Linha Verde Saúde: 080 080 0800

ARQUITETURA — PROMPT-CHAIN 5 CAMADAS:
CAMADA 1 ESCUTA: Lê a mensagem na íntegra. Identifica tema central.
CAMADA 2 ANÁLISE LASER: Avalia risco. Identifica sinais de alerta. Verifica dados sensíveis.
CAMADA 3 GERAÇÃO: Escreve rascunho empático + passos práticos.
CAMADA 4 MODERAÇÃO: Verifica conformidade EU AI Act, RGPD e saúde mental. Remove dados identificáveis.
CAMADA 5 PERSONALIZAÇÃO: Ajusta ao perfil MVCO (Maria Verde=iniciante; Maria Laranja=consolidada; Maria Vermelha=em crise; Maria Azul=mentora).

REGRAS ABSOLUTAS:
1. NUNCA interages diretamente com membras.
2. NUNCA reproduzes dados pessoais identificáveis.
3. NUNCA diagnosticas condições de saúde mental.
4. NUNCA minimizas sofrimento.
5. NUNCA invalidas o sentimento da Maria.
6. NUNCA crias dependência emocional.
7. SEMPRE manténs tom lusófono (PT com sensibilidade BR e AO).
8. SEMPRE encaminhas para recursos profissionais quando risco = alto.
9. SEMPRE lembras a fundadora de adaptar o rascunho à sua voz.

Responde SEMPRE em JSON válido, sem texto antes ou depois:

{
  "analise_laser": "2–3 frases. Tema central, dimensão emocional/financeira/relacional, sinais de alerta. Sem dados pessoais.",
  "risco": "baixo | médio | alto",
  "risco_justificacao": "1 frase objetiva.",
  "conformidade_rgpd": "OK | ATENÇÃO — nota se há dados sensíveis",
  "resposta_empatica": "80–120 palavras. Valida sentimento sem amplificar. Tom de amiga. Sem diagnósticos.",
  "passos_praticos": ["Passo 1 — concreto, próximos 7 dias", "Passo 2", "Passo 3"],
  "encaminhamento": {
    "canal": "canal sugerido na Circle",
    "convite": "1–2 frases convidando ao fórum"
  },
  "nota_risco_alto": "APENAS se risco=alto: encaminhamento gentil para profissionais + recursos PT/BR/AO relevantes. Nota interna — não publicar.",
  "nota_moderadora": "Orientação para a fundadora: o que adaptar, se deve fazer follow-up. Máx. 2 frases."
}`;

const EXEMPLOS = [
  "Lanço o meu produto há 6 meses e não consigo vender. Sinto que falhei.",
  "O banco recusou-me financiamento pela terceira vez. Não sei mais o que fazer.",
  "Tenho vergonha de cobrar o que vale o meu trabalho às clientes.",
  "A minha sócia quer sair do negócio e não sei como continuar sozinha.",
  "Estou a pensar abandonar tudo — o negócio, o relacionamento. Não aguento mais."
];

const RISCO_CONFIG = {
  "baixo": { cor: "#5f7060", bg: "rgba(95,112,96,0.12)", label: "Risco Baixo", icon: "🌿" },
  "médio": { cor: "#b8935a", bg: "rgba(184,147,90,0.12)", label: "Risco Médio", icon: "🌙" },
  "alto":  { cor: "#b85c3e", bg: "rgba(184,92,62,0.12)", label: "Risco Elevado — Atenção", icon: "🔴" }
};

const FLUXO_STEPS = [
  { icon: "👂", label: "Escuta", sub: "Dados da comunidade" },
  { icon: "🔬", label: "Análise LASER", sub: "5 camadas" },
  { icon: "✍️", label: "Sugestão", sub: "Rascunho gerado" },
  { icon: "✅", label: "Validação Humana", sub: "Safety Layer" },
];

function FluxoDiagrama({ activeStep }) {
  return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 0, marginBottom: 44, flexWrap: "wrap" }}>
      {FLUXO_STEPS.map((step, i) => (
        <div key={i} style={{ display: "flex", alignItems: "center" }}>
          <div style={{
            display: "flex", flexDirection: "column", alignItems: "center", gap: 5,
            padding: "10px 14px",
            background: activeStep === i ? "rgba(122,59,46,0.1)" : "rgba(44,31,26,0.04)",
            border: `1px solid ${activeStep === i ? "rgba(122,59,46,0.35)" : "rgba(44,31,26,0.1)"}`,
            borderRadius: 8, transition: "all 0.4s", minWidth: 82
          }}>
            <span style={{ fontSize: 18 }}>{step.icon}</span>
            <span style={{ fontSize: 9, fontWeight: 700, letterSpacing: "1.2px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: activeStep === i ? "#7a3b2e" : "rgba(44,31,26,0.45)", textAlign: "center" }}>{step.label}</span>
            <span style={{ fontSize: 9, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.3)", textAlign: "center" }}>{step.sub}</span>
          </div>
          {i < FLUXO_STEPS.length - 1 && <div style={{ fontSize: 13, color: "rgba(44,31,26,0.2)", padding: "0 5px" }}>→</div>}
        </div>
      ))}
    </div>
  );
}

function PassoCard({ passo, idx, delay }) {
  const [vis, setVis] = useState(false);
  useEffect(() => { const t = setTimeout(() => setVis(true), delay); return () => clearTimeout(t); }, [delay]);
  return (
    <div style={{ display: "flex", gap: 14, alignItems: "flex-start", opacity: vis ? 1 : 0, transform: vis ? "translateY(0)" : "translateY(10px)", transition: "all 0.5s ease", padding: "14px 18px", background: "rgba(44,31,26,0.04)", border: "1px solid rgba(44,31,26,0.08)", borderRadius: 6 }}>
      <div style={{ width: 26, height: 26, borderRadius: "50%", background: "rgba(184,92,62,0.12)", border: "1px solid rgba(184,92,62,0.3)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontFamily: "'Georgia', serif", fontSize: 12, color: "#7a3b2e", fontStyle: "italic" }}>{idx}</div>
      <p style={{ fontSize: 14, lineHeight: 1.7, color: "rgba(44,31,26,0.75)", margin: 0, fontFamily: "system-ui, sans-serif" }}>{passo.replace(/^Passo \d+\s*[—–-]\s*/, "")}</p>
    </div>
  );
}

function Secao({ titulo, icon, children, delay = 0 }) {
  const [vis, setVis] = useState(false);
  useEffect(() => { const t = setTimeout(() => setVis(true), delay); return () => clearTimeout(t); }, [delay]);
  return (
    <div style={{ opacity: vis ? 1 : 0, transform: vis ? "translateY(0)" : "translateY(14px)", transition: "all 0.6s ease", marginBottom: 24 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 10, fontSize: 10, fontWeight: 700, letterSpacing: "2.5px", textTransform: "uppercase", color: "#7a3b2e", fontFamily: "system-ui, sans-serif" }}>
        <span>{icon}</span>{titulo}
      </div>
      {children}
    </div>
  );
}

export default function OráculoMaria() {
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [resultado, setResultado] = useState(null);
  const [erro, setErro] = useState(null);
  const [copiado, setCopiado] = useState(false);
  const [activeStep, setActiveStep] = useState(-1);
  const textareaRef = useRef(null);

  const usarExemplo = (ex) => { setInput(ex); setResultado(null); setErro(null); textareaRef.current?.focus(); };

  const consultar = async () => {
    if (!input.trim() || loading) return;
    setLoading(true); setResultado(null); setErro(null); setActiveStep(0);
    setTimeout(() => setActiveStep(1), 700);
    setTimeout(() => setActiveStep(2), 1900);
    try {
      const res = await fetch("/api/oracle", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: input.trim() })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setActiveStep(3);
      setTimeout(() => setActiveStep(-1), 2200);
      setResultado(data);
    } catch (e) {
      setErro(e.message || "O Oráculo não conseguiu processar esta mensagem. Tenta novamente.");
      setActiveStep(-1);
    } finally {
      setLoading(false);
    }
  };

  const copiarRascunho = () => {
    if (!resultado) return;
    const texto = `📝 RASCUNHO — Oráculo Maria · MVCO\n\n🔬 ANÁLISE LASER:\n${resultado.analise_laser}\n\n🔒 RGPD: ${resultado.conformidade_rgpd}\n\n💬 RESPOSTA SUGERIDA:\n${resultado.resposta_empatica}\n\n✅ Próximos passos:\n${resultado.passos_praticos.map((p,i)=>`${i+1}. ${p}`).join("\n")}\n\n🔁 Canal: ${resultado.encaminhamento?.canal}\n${resultado.encaminhamento?.convite}${resultado.nota_risco_alto ? `\n\n⚠️ NOTA INTERNA (não publicar):\n${resultado.nota_risco_alto}` : ""}\n\n📋 NOTA MODERADORA:\n${resultado.nota_moderadora}\n\n— A IA prepara, o humano publica. 💛`;
    navigator.clipboard.writeText(texto);
    setCopiado(true);
    setTimeout(() => setCopiado(false), 2500);
  };

  const riscoConf = resultado ? RISCO_CONFIG[resultado.risco] || RISCO_CONFIG["baixo"] : null;

  return (
    <div style={{ minHeight: "100vh", background: "#ede8e1", fontFamily: "'Georgia', 'Times New Roman', serif", color: "#2c1f1a" }}>
      <style>{`
        * { box-sizing: border-box; }
        body { margin: 0; background: #ede8e1; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes shimmer { 0% { background-position: -200% center; } 100% { background-position: 200% center; } }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes float { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-6px); } }
        textarea { outline: none; }
        button { cursor: pointer; transition: all 0.2s; }
        button:hover { opacity: 0.82; }
        .chip:hover { background: rgba(122,59,46,0.1) !important; border-color: rgba(122,59,46,0.35) !important; color: #7a3b2e !important; }
      `}</style>

      {/* Navbar */}
      <div style={{ borderBottom: "1px solid rgba(44,31,26,0.1)", padding: "14px 40px", display: "flex", alignItems: "center", justifyContent: "space-between", background: "#ede8e1", position: "sticky", top: 0, zIndex: 100 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <img src={LOGO_SRC} alt="MVCO Logo" style={{ width: 36, height: 36, objectFit: "contain" }} />
          <span style={{ fontFamily: "'Georgia', serif", fontSize: 17, fontWeight: 400, color: "#2c1f1a", letterSpacing: "1px" }}>MVCO.</span>
        </div>
        <div style={{ fontSize: 9, letterSpacing: "2.5px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.35)" }}>
          Oráculo Maria · Back-office IA · Uso interno
        </div>
      </div>

      <div style={{ maxWidth: 720, margin: "0 auto", padding: "52px 24px 80px" }}>

        {/* Hero */}
        <div style={{ textAlign: "center", marginBottom: 52 }}>
          <div style={{ fontSize: 9, letterSpacing: "3px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.38)", marginBottom: 28 }}>
            PORTUGAL · EMPREENDEDORAS CRIATIVAS · MARIA VAI COM AS OUTRAS
          </div>

          {/* Logo animado */}
          <div style={{ animation: "float 4s ease-in-out infinite", marginBottom: 24 }}>
            <img src={LOGO_SRC} alt="MVCO" style={{ width: loading ? 72 : 64, height: loading ? 72 : 64, objectFit: "contain", transition: "all 0.5s", filter: loading ? "drop-shadow(0 0 12px rgba(184,92,62,0.5))" : "none" }} />
          </div>

          <h1 style={{ fontFamily: "'Georgia', serif", fontWeight: 400, fontSize: "clamp(30px, 5vw, 44px)", color: "#2c1f1a", margin: "0 0 8px", lineHeight: 1.15 }}>
            Oráculo <span style={{ fontStyle: "italic", color: "#b85c3e" }}>Maria</span>
          </h1>
          <p style={{ fontSize: 13, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.45)", fontStyle: "italic", margin: "0 0 18px" }}>
            "A IA prepara, o humano publica."
          </p>
          <p style={{ fontSize: 14, color: "rgba(44,31,26,0.58)", maxWidth: 520, margin: "0 auto", lineHeight: 1.8, fontFamily: "system-ui, sans-serif" }}>
            Assistente de back-office da comunidade. Partilha uma mensagem recebida — o Oráculo analisa em 5 camadas, gera um rascunho empático e conforme com RGPD e EU AI Act.
          </p>

          {/* Badges legais */}
          <div style={{ display: "flex", justifyContent: "center", gap: 8, marginTop: 20, flexWrap: "wrap" }}>
            {["🔒 RGPD", "⚖️ EU AI Act", "🧠 OPP/OMS", "👁️ Human-in-the-loop"].map((b, i) => (
              <span key={i} style={{ fontSize: 10, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.45)", background: "rgba(44,31,26,0.06)", border: "1px solid rgba(44,31,26,0.1)", borderRadius: 100, padding: "4px 12px", letterSpacing: "0.5px" }}>{b}</span>
            ))}
          </div>
        </div>

        {/* Fluxo */}
        <FluxoDiagrama activeStep={activeStep} />

        {/* Exemplos */}
        <div style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 9, letterSpacing: "2.5px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.3)", marginBottom: 10 }}>Exemplos de mensagens</div>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
            {EXEMPLOS.map((ex, i) => (
              <button key={i} className="chip" onClick={() => usarExemplo(ex)} style={{ background: "rgba(44,31,26,0.05)", border: "1px solid rgba(44,31,26,0.12)", borderRadius: 100, padding: "6px 14px", fontSize: 11, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.5)" }}>
                {ex.length > 55 ? ex.slice(0, 52) + "…" : ex}
              </button>
            ))}
          </div>
        </div>

        {/* Input */}
        <div style={{ background: "rgba(255,251,246,0.8)", border: "1px solid rgba(44,31,26,0.12)", borderRadius: 10, padding: "22px 26px", marginBottom: 18, boxShadow: "0 2px 16px rgba(44,31,26,0.05)" }}>
          <div style={{ fontSize: 9, letterSpacing: "2.5px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.35)", marginBottom: 12 }}>Mensagem recebida na comunidade</div>
          <textarea ref={textareaRef} value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => { if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) consultar(); }} placeholder="Cola aqui a mensagem da membra..." rows={5} style={{ width: "100%", background: "transparent", border: "none", resize: "vertical", fontSize: 15, fontFamily: "'Georgia', serif", fontStyle: "italic", color: "#2c1f1a", lineHeight: 1.75, caretColor: "#b85c3e" }} />
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 12, paddingTop: 12, borderTop: "1px solid rgba(44,31,26,0.08)" }}>
            <span style={{ fontSize: 11, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.28)" }}>{input.length > 0 ? `${input.length} caracteres` : "⌘+Enter para consultar"}</span>
            <button onClick={consultar} disabled={loading || !input.trim()} style={{ background: loading || !input.trim() ? "rgba(44,31,26,0.08)" : "linear-gradient(135deg, #7a3b2e, #b85c3e)", border: "none", borderRadius: 6, padding: "12px 30px", fontSize: 11, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: loading || !input.trim() ? "rgba(44,31,26,0.3)" : "#f7f0e8", cursor: loading || !input.trim() ? "not-allowed" : "pointer" }}>
              {loading ? "A analisar…" : "Consultar o Oráculo"}
            </button>
          </div>
        </div>

        {/* Loading */}
        {loading && (
          <div style={{ textAlign: "center", padding: "36px 0", animation: "fadeIn 0.3s ease" }}>
            <div style={{ width: 28, height: 28, border: "2px solid rgba(184,92,62,0.15)", borderTop: "2px solid #b85c3e", borderRadius: "50%", animation: "spin 0.9s linear infinite", margin: "0 auto 16px" }} />
            <p style={{ fontSize: 13, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.4)", fontStyle: "italic", margin: 0 }}>Análise LASER em curso… 5 camadas</p>
            <div style={{ width: 140, height: 1, background: "rgba(44,31,26,0.08)", margin: "16px auto 0", overflow: "hidden" }}>
              <div style={{ height: "100%", width: "60%", background: "linear-gradient(90deg, transparent, #b85c3e, transparent)", backgroundSize: "200% 100%", animation: "shimmer 1.5s infinite linear" }} />
            </div>
          </div>
        )}

        {/* Erro */}
        {erro && (
          <div style={{ padding: 20, background: "rgba(184,92,62,0.08)", border: "1px solid rgba(184,92,62,0.2)", borderRadius: 8, textAlign: "center", fontSize: 14, fontFamily: "system-ui, sans-serif", color: "#7a3b2e" }}>{erro}</div>
        )}

        {/* Resultado */}
        {resultado && (
          <div style={{ animation: "fadeIn 0.6s ease both" }}>

            {/* Risco + RGPD */}
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 32 }}>
              <div style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "9px 18px", borderRadius: 100, background: riscoConf.bg, border: `1px solid ${riscoConf.cor}30`, fontFamily: "system-ui, sans-serif" }}>
                <span>{riscoConf.icon}</span>
                <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: riscoConf.cor }}>{riscoConf.label}</span>
                <span style={{ fontSize: 11, color: "rgba(44,31,26,0.4)", fontStyle: "italic" }}>— {resultado.risco_justificacao}</span>
              </div>
              {resultado.conformidade_rgpd && (
                <div style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "9px 16px", borderRadius: 100, background: resultado.conformidade_rgpd === "OK" ? "rgba(95,112,96,0.1)" : "rgba(184,147,90,0.12)", border: `1px solid ${resultado.conformidade_rgpd === "OK" ? "rgba(95,112,96,0.25)" : "rgba(184,147,90,0.3)"}`, fontFamily: "system-ui, sans-serif" }}>
                  <span>{resultado.conformidade_rgpd === "OK" ? "🔒" : "⚠️"}</span>
                  <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: "1.5px", textTransform: "uppercase", color: resultado.conformidade_rgpd === "OK" ? "#5f7060" : "#b8935a" }}>RGPD: {resultado.conformidade_rgpd}</span>
                </div>
              )}
            </div>

            <Secao titulo="Análise LASER" icon="🔬" delay={80}>
              <div style={{ background: "rgba(122,59,46,0.06)", border: "1px solid rgba(122,59,46,0.12)", borderRadius: 8, padding: "18px 22px" }}>
                <p style={{ fontSize: 14, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.7)", lineHeight: 1.75, margin: 0 }}>{resultado.analise_laser}</p>
              </div>
            </Secao>

            <Secao titulo="Rascunho de resposta" icon="✍️" delay={200}>
              <div style={{ background: "rgba(255,251,246,0.9)", border: "1px solid rgba(44,31,26,0.1)", borderRadius: 8, padding: "26px 30px", position: "relative", boxShadow: "0 2px 12px rgba(44,31,26,0.05)" }}>
                <div style={{ position: "absolute", top: 10, left: 18, fontFamily: "'Georgia', serif", fontSize: "4rem", color: "#b85c3e", opacity: 0.12, lineHeight: 1 }}>"</div>
                <p style={{ fontSize: 16, fontFamily: "'Georgia', serif", fontStyle: "italic", color: "#2c1f1a", lineHeight: 1.8, margin: "12px 0 0" }}>{resultado.resposta_empatica}</p>
              </div>
            </Secao>

            <Secao titulo="Passos práticos (próximos 7 dias)" icon="🗺️" delay={340}>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {resultado.passos_praticos?.map((p, i) => <PassoCard key={i} passo={p} idx={i + 1} delay={400 + i * 120} />)}
              </div>
            </Secao>

            <Secao titulo="Encaminhamento para a comunidade" icon="🔁" delay={620}>
              <div style={{ background: "rgba(95,112,96,0.07)", border: "1px solid rgba(95,112,96,0.16)", borderRadius: 8, padding: "18px 22px" }}>
                <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: "1.5px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "#5f7060", marginBottom: 8 }}>Canal sugerido</div>
                <div style={{ fontSize: 14, fontFamily: "'Georgia', serif", color: "#2c1f1a", marginBottom: 10 }}>📍 {resultado.encaminhamento?.canal}</div>
                <p style={{ fontSize: 13, fontFamily: "'Georgia', serif", fontStyle: "italic", color: "rgba(44,31,26,0.6)", lineHeight: 1.7, margin: 0 }}>{resultado.encaminhamento?.convite}</p>
              </div>
            </Secao>

            {resultado.nota_moderadora && (
              <Secao titulo="Nota para a moderadora" icon="📋" delay={740}>
                <div style={{ background: "rgba(44,31,26,0.04)", border: "1px solid rgba(44,31,26,0.1)", borderRadius: 8, padding: "16px 20px" }}>
                  <p style={{ fontSize: 13, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.65)", lineHeight: 1.7, margin: 0 }}>{resultado.nota_moderadora}</p>
                </div>
              </Secao>
            )}

            {resultado.nota_risco_alto && (
              <Secao titulo="⚠️ Atenção — Nota interna (NÃO publicar)" icon="🔴" delay={860}>
                <div style={{ background: "rgba(184,92,62,0.08)", border: "1px solid rgba(184,92,62,0.28)", borderRadius: 8, padding: "18px 22px" }}>
                  <p style={{ fontSize: 14, fontFamily: "system-ui, sans-serif", color: "#7a3b2e", lineHeight: 1.75, margin: 0 }}>{resultado.nota_risco_alto}</p>
                </div>
              </Secao>
            )}

            {/* Ações */}
            <div style={{ display: "flex", gap: 12, marginTop: 32, flexWrap: "wrap", animation: "fadeIn 0.6s ease 0.9s both" }}>
              <button onClick={copiarRascunho} style={{ flex: 1, minWidth: 180, background: copiado ? "rgba(95,112,96,0.15)" : "linear-gradient(135deg, #7a3b2e, #b85c3e)", border: copiado ? "1px solid rgba(95,112,96,0.3)" : "none", borderRadius: 6, padding: "13px 22px", fontSize: 11, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: copiado ? "#5f7060" : "#f7f0e8" }}>
                {copiado ? "✓ Copiado!" : "Copiar rascunho completo"}
              </button>
              <button onClick={() => { setResultado(null); setInput(""); setErro(null); setActiveStep(-1); }} style={{ background: "transparent", border: "1px solid rgba(44,31,26,0.15)", borderRadius: 6, padding: "13px 22px", fontSize: 11, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.45)" }}>
                Nova consulta
              </button>
            </div>

            <div style={{ marginTop: 22, padding: "13px 18px", background: "rgba(44,31,26,0.04)", border: "1px solid rgba(44,31,26,0.07)", borderRadius: 8, textAlign: "center", animation: "fadeIn 0.6s ease 1.1s both" }}>
              <p style={{ fontSize: 11, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.38)", margin: 0, fontStyle: "italic", lineHeight: 1.6 }}>
                💛 Relê, adapta à tua voz e ao que conheces da situação antes de publicar. A IA apoia; o acolhimento é teu.
              </p>
            </div>
          </div>
        )}

        {/* Footer */}
        <div style={{ marginTop: 64, textAlign: "center", borderTop: "1px solid rgba(44,31,26,0.1)", paddingTop: 32 }}>
          <img src={LOGO_SRC} alt="MVCO" style={{ width: 40, height: 40, objectFit: "contain", marginBottom: 8 }} />
          <div style={{ fontFamily: "'Georgia', serif", fontStyle: "italic", fontSize: 17, color: "#7a3b2e", marginBottom: 4 }}>MVCO.</div>
          <div style={{ fontSize: 9, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.22)", marginBottom: 22 }}>Maria Vai Com as Outras</div>
          <div style={{ display: "flex", justifyContent: "center", gap: 24, flexWrap: "wrap", marginBottom: 20 }}>
            {[{ icon: "💰", label: "Fundo Maria", sub: "Micro-financiamento" }, { icon: "✦", label: "Oráculo Maria", sub: "Back-office IA" }, { icon: "🌊", label: "Comunidade", sub: "Privada & Imersiva" }].map((p, i) => (
              <div key={i} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}>
                <span style={{ fontSize: 17 }}>{p.icon}</span>
                <span style={{ fontSize: 9, fontWeight: 700, letterSpacing: "1.5px", textTransform: "uppercase", fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.32)" }}>{p.label}</span>
                <span style={{ fontSize: 9, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.2)" }}>{p.sub}</span>
              </div>
            ))}
          </div>
          <div style={{ fontSize: 10, fontFamily: "system-ui, sans-serif", color: "rgba(44,31,26,0.2)", letterSpacing: "0.5px" }}>
            Conforme RGPD (UE) 2016/679 · EU AI Act (UE) 2024/1689 · Boas Práticas OPP/OMS
          </div>
        </div>
      </div>
    </div>
  );
}
